Def:
=if(vMeasure='Units', Aggr(Rank(count({$<[Investor Status]-={'Purchased'}, [Funding Rolling 13 Month Flag]={Yes}>}[Loan Number]), 4, 1), Investor) & ', ' & Investor,
	Aggr(Rank(sum({$<[Investor Status]-={'Purchased'}, [Funding Rolling 13 Month Flag]={Yes}>}[Loan Amount]), 4, 1), Investor) & ', ' & Investor 	
)

=if(vMeasure='Units', Aggr(Rank(count({$<[Investor Status]-={'Purchased'}, [Funding Rolling 13 Month Flag]={Yes}>}[Loan Number]), 4, 1), [Warehouse Co Name]) & ', ' & [Warehouse Co Name],
	Aggr(Rank(sum({$<[Investor Status]-={'Purchased'}, [Funding Rolling 13 Month Flag]={Yes}>}[Loan Amount]), 4, 1), [Warehouse Co Name]) & ', ' & [Warehouse Co Name] 	
)

